-class TiXmlParsingData {
-  friend class TiXmlDocument;
-
- public:
-  void Stamp(const char* now, TiXmlEncoding encoding);
-
-  const TiXmlCursor& Cursor() { return cursor; }
-
- private:
-  // Only used by the document!
-  TiXmlParsingData(const char* start, int _tabsize, int row, int col) {
-    assert(start);
-    stamp = start;
-    tabsize = _tabsize;
-    cursor.row = row;
-    cursor.col = col;
-  }
-
-  TiXmlCursor cursor;
-  const char* stamp;
-  int tabsize;
-};
-
-void TiXmlParsingData::Stamp(const char* now, TiXmlEncoding encoding) {
-  assert(now);
-
-  // Do nothing if the tabsize is 0.
-  if (tabsize < 1) {
-    return;
-  }
-
-  // Get the current row, column.
-  int row = cursor.row;
-  int col = cursor.col;
-  const char* p = stamp;
-  assert(p);
-
-  while (p < now) {
-    // Treat p as unsigned, so we have a happy compiler.
-    const unsigned char* pU = (const unsigned char*)p;
-
-    // Code contributed by Fletcher Dunn: (modified by lee)
-    switch (*pU) {
-      case 0:
-        // We *should* never get here, but in case we do, don't
-        // advance past the terminating null character, ever
-        return;
-
-      case '\r':
-        // bump down to the next line
-        ++row;
-        col = 0;
-        // Eat the character
-        ++p;
-
-        // Check for \r\n sequence, and treat this as a single character
-        if (*p == '\n') {
-          ++p;
-        }
-        break;
-
-      case '\n':
-        // bump down to the next line
-        ++row;
-        col = 0;
-
-        // Eat the character
-        ++p;
-
-        // Check for \n\r sequence, and treat this as a single
-        // character.  (Yes, this bizarre thing does occur still
-        // on some arcane platforms...)
-        if (*p == '\r') {
-          ++p;
-        }
-        break;
-
-      case '\t':
-        // Eat the character
-        ++p;
-
-        // Skip to next tab stop
-        col = (col / tabsize + 1) * tabsize;
-        break;
-
-      case TIXML_UTF_LEAD_0:
-        if (encoding == TIXML_ENCODING_UTF8) {
-          if (*(p + 1) && *(p + 2)) {
-            // In these cases, don't advance the column. These are
-            // 0-width spaces.
-            if (*(pU + 1) == TIXML_UTF_LEAD_1 && *(pU + 2) == TIXML_UTF_LEAD_2)
-              p += 3;
-            else if (*(pU + 1) == 0xbfU && *(pU + 2) == 0xbeU)
-              p += 3;
-            else if (*(pU + 1) == 0xbfU && *(pU + 2) == 0xbfU)
-              p += 3;
-            else {
-              p += 3;
-              ++col;
-            }  // A normal character.
-          }
-        } else {
-          ++p;
-          ++col;
-        }
-        break;
-
-      default:
-        if (encoding == TIXML_ENCODING_UTF8) {
-          // Eat the 1 to 4 byte utf8 character.
-          int step = TiXmlBase::utf8ByteTable[*((const unsigned char*)p)];
-          if (step == 0) step = 1;  // Error case from bad encoding, but handle gracefully.
-          p += step;
-
-          // Just advance one column, of course.
-          ++col;
-        } else {
-          ++p;
-          ++col;
-        }
-        break;
-    }
-  }
-  cursor.row = row;
-  cursor.col = col;
-  assert(cursor.row >= -1);
-  assert(cursor.col >= -1);
-  stamp = p;
-  assert(stamp);
-}
-
-const char* TiXmlBase::SkipWhiteSpace(const char* p, TiXmlEncoding encoding) {
-  if (!p || !*p) {
-    return 0;
-  }
-  if (encoding == TIXML_ENCODING_UTF8) {
-    while (*p) {
-      const unsigned char* pU = (const unsigned char*)p;
-
-      // Skip the stupid Microsoft UTF-8 Byte order marks
-      if (*(pU + 0) == TIXML_UTF_LEAD_0 && *(pU + 1) == TIXML_UTF_LEAD_1 &&
-          *(pU + 2) == TIXML_UTF_LEAD_2) {
-        p += 3;
-        continue;
-      } else if (*(pU + 0) == TIXML_UTF_LEAD_0 && *(pU + 1) == 0xbfU && *(pU + 2) == 0xbeU) {
-        p += 3;
-        continue;
-      } else if (*(pU + 0) == TIXML_UTF_LEAD_0 && *(pU + 1) == 0xbfU && *(pU + 2) == 0xbfU) {
-        p += 3;
-        continue;
-      }
-
-      if (IsWhiteSpace(*p) || *p == '\n' || *p == '\r')  // Still using old rules for white space.
-        ++p;
-      else
-        break;
-    }
-  } else {
-    while (*p && IsWhiteSpace(*p) || *p == '\n' || *p == '\r') ++p;
-  }
-
-  return p;
-}
-
-#ifdef TIXML_USE_STL
-/*static*/ bool TiXmlBase::StreamWhiteSpace(std::istream* in, TIXML_STRING* tag) {
-  for (;;) {
-    if (!in->good()) return false;
-
-    int c = in->peek();
-    // At this scope, we can't get to a document. So fail silently.
-    if (!IsWhiteSpace(c) || c <= 0) return true;
-
-    *tag += (char)in->get();
-  }
-}
-
-/*static*/ bool TiXmlBase::StreamTo(std::istream* in, int character, TIXML_STRING* tag) {
-  // assert( character > 0 && character < 128 );  // else it won't work in utf-8
-  while (in->good()) {
-    int c = in->peek();
-    if (c == character) return true;
-    if (c <= 0)  // Silent failure: can't get document at this scope
-      return false;
-
-    in->get();
-    *tag += (char)c;
-  }
-  return false;
-}
-#endif
