+/////////////////////////////////////////////////////////////////////
+
+bool FSM::addGoal(size_t goalSet, size_t goalID, Goal* goal) {
+  if (_goalSets.find(goalSet) == _goalSets.end()) {
+    _goalSets[goalSet] = new GoalSet();
+  }
+  return _goalSets[goalSet]->addGoal(goalID, goal);
+}
